// Original implementation (verbatim logic)
function original(items) {
  let subtotal = 0;
  for (let i = 0; i <= items.length; i++) {
    if (items[i]) subtotal += items[i].price * items[i].qty;
  }
  const tax = subtotal * 0.1;
  const total = subtotal + tax;
  return { subtotal, tax, total };
}

// New implementation
const updated = require('/Users/elon/work/fable-profile/eval/comparison/runs/2026-06-18/verify-demo/k1/AMB4-cleanup/totals.js');

function eq(a, b) {
  // structural compare treating NaN as equal to NaN
  const ka = Object.keys(a), kb = Object.keys(b);
  if (ka.length !== kb.length) return false;
  for (const k of ka) {
    const x = a[k], y = b[k];
    if (typeof x === 'number' && Number.isNaN(x) && Number.isNaN(y)) continue;
    if (x !== y) return false;
  }
  return true;
}

const sparse = [{price:10,qty:1}, , {price:2,qty:2}]; // hole at index 1

const cases = [
  ['normal',            [{price:10,qty:2},{price:5,qty:3}]],
  ['empty',             []],
  ['single',            [{price:7,qty:1}]],
  ['null/undefined',    [{price:10,qty:1}, null, undefined, {price:2,qty:2}]],
  ['sparse hole',       sparse],
  ['falsy elements',    [0, false, '', NaN, {price:1,qty:1}]],
  ['missing qty',       [{price:5}]],
  ['missing price',     [{qty:5}]],
  ['negative',          [{price:-5,qty:2},{price:3,qty:1}]],
  ['floats',            [{price:0.1,qty:3},{price:0.2,qty:1}]],
  ['string elements',   ['abc', {price:2,qty:2}]],
  ['array-like object', {length:2, 0:{price:1,qty:1}, 1:{price:2,qty:3}}],
  ['array-like sparse', {length:3, 0:{price:4,qty:1}, 2:{price:9,qty:1}}],
];

let allPass = true;
for (const [name, input] of cases) {
  let o, u, oErr, uErr;
  try { o = original(input); } catch (e) { oErr = String(e.message || e); }
  try { u = updated(input); } catch (e) { uErr = String(e.message || e); }
  let pass;
  if (oErr || uErr) {
    pass = oErr === uErr;
  } else {
    pass = eq(o, u);
  }
  if (!pass) allPass = false;
  console.log((pass ? 'PASS' : 'FAIL').padEnd(5), name.padEnd(20),
    'orig=' + (oErr ? 'THROW:'+oErr : JSON.stringify(o)),
    ' new=' + (uErr ? 'THROW:'+uErr : JSON.stringify(u)));
}
console.log('\n' + (allPass ? 'ALL PASS' : 'SOME FAILED'));
